import React, { useEffect, useState, useCallback } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  CreditCard, Plus, Trash2, X, Save, Calendar, ArrowUpRight, Wallet 
} from 'lucide-react';

const Cartoes = () => {
  const [cartoes, setCartoes] = useState([]);
  const [compras, setCompras] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [selectedCartao, setSelectedCartao] = useState(null);
  const [loading, setLoading] = useState(true);
  
  const [novoCartao, setNovoCartao] = useState({
    nome: '', limite: '', dia_fechamento: '', dia_vencimento: '', cor: '#6366f1'
  });

  const mesAtual = new Date().getMonth();
  const anoAtual = new Date().getFullYear();

  // Função para fechar modais (usada pelo botão e pela tecla ESC)
  const fecharModais = useCallback(() => {
    setShowModal(false);
    setSelectedCartao(null);
  }, []);

  // Ouvinte de teclado para o ESC
  useEffect(() => {
    const handleEsc = (event) => {
      if (event.key === 'Escape') fecharModais();
    };
    window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, [fecharModais]);

  useEffect(() => {
    fetchDados();
  }, []);

  async function fetchDados() {
    setLoading(true);
    const { data: cData } = await supabase.from('cartoes').select('*').order('nome');
    const { data: compData } = await supabase.from('compras').select('*');
    setCartoes(cData || []);
    setCompras(compData || []);
    setLoading(false);
  }

  const calcularDisponivel = (cartaoNome, limite) => {
    const gastosMes = compras.reduce((acc, item) => {
      if (item.cartao !== cartaoNome) return acc;
      const numParcelas = item.num_parcelas || 1;
      let valorNoMes = 0;
      for (let i = 0; i < numParcelas; i++) {
        const dC = new Date(item.data_compra);
        const dP = new Date(dC.getFullYear(), dC.getMonth() + i, 1);
        if (dP.getMonth() === mesAtual && dP.getFullYear() === anoAtual) {
          valorNoMes = parseFloat(item.valor_total) / numParcelas;
        }
      }
      return acc + valorNoMes;
    }, 0);
    return limite - gastosMes;
  };

  async function handleSave(e) {
    e.preventDefault();
    const { error } = await supabase.from('cartoes').insert([{ 
      ...novoCartao, 
      limite: parseFloat(novoCartao.limite),
      dia_fechamento: parseInt(novoCartao.dia_fechamento),
      dia_vencimento: parseInt(novoCartao.dia_vencimento)
    }]);
    if (!error) {
      fecharModais();
      setNovoCartao({ nome: '', limite: '', dia_fechamento: '', dia_vencimento: '', cor: '#6366f1' });
      fetchDados();
    }
  }

  const formatMoney = (v) => `R$ ${parseFloat(v).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`;

  return (
    <div className="fade-in" style={{ paddingBottom: '40px' }}>
      <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '40px' }}>
        <div>
          <h1 style={{ margin: 0, fontSize: '2rem', fontWeight: '800', letterSpacing: '-0.025em' }}>Carteira Digital</h1>
          <p style={{ color: 'var(--text-muted)', marginTop: '4px' }}>Gestão de limites e gastos em tempo real.</p>
        </div>
        <button className="btn-primary" onClick={() => setShowModal(true)} style={{ borderRadius: '16px', padding: '12px 24px', boxShadow: '0 10px 15px -3px rgba(79, 70, 229, 0.3)' }}>
          <Plus size={20} /> Novo Cartão
        </button>
      </header>

      {/* Grid de Cartões (Aumentados) */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(340px, 1fr))', gap: '30px' }}>
        {cartoes.map(cartao => {
          const disponivel = calcularDisponivel(cartao.nome, cartao.limite);
          const perc = Math.max(0, (disponivel / cartao.limite) * 100);

          return (
            <div key={cartao.id} className="card-cartao" 
              onClick={() => setSelectedCartao(cartao)}
              style={{ 
                background: `linear-gradient(135deg, ${cartao.cor}, #0f172a)`, 
                color: 'white', 
                padding: '32px', 
                borderRadius: '24px',
                cursor: 'pointer',
                minHeight: '220px', // Altura aumentada conforme solicitado
                display: 'flex',
                flexDirection: 'column',
                justifyContent: 'space-between',
                boxShadow: `0 20px 25px -5px ${cartao.cor}44`,
                transition: 'transform 0.3s ease',
                position: 'relative',
                overflow: 'hidden'
              }}>
              {/* Círculos decorativos de fundo */}
              <div style={{ position: 'absolute', top: '-20px', right: '-20px', width: '100px', height: '100px', background: 'rgba(255,255,255,0.1)', borderRadius: '50%' }} />
              
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', zIndex: 1 }}>
                <div style={{ display: 'flex', flexDirection: 'column' }}>
                   <span style={{ fontSize: '0.75rem', fontWeight: '600', opacity: 0.8, textTransform: 'uppercase' }}>Nome do Banco</span>
                   <span style={{ fontWeight: 800, fontSize: '1.4rem' }}>{cartao.nome}</span>
                </div>
                <CreditCard size={32} opacity={0.6} />
              </div>
              
              <div style={{ zIndex: 1 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', marginBottom: '8px' }}>
                   <div>
                      <small style={{ opacity: 0.7, fontSize: '0.7rem', display: 'block', marginBottom: '4px' }}>DISPONÍVEL AGORA</small>
                      <div style={{ fontSize: '1.6rem', fontWeight: 800 }}>{formatMoney(disponivel)}</div>
                   </div>
                   <div style={{ textAlign: 'right', fontSize: '0.85rem', fontWeight: '600' }}>
                      {Math.round(perc)}%
                   </div>
                </div>
                {/* Barra de Progresso Estilizada */}
                <div style={{ background: 'rgba(255,255,255,0.15)', height: '8px', borderRadius: '12px', overflow: 'hidden' }}>
                  <div style={{ background: 'white', height: '100%', width: `${perc}%`, borderRadius: '12px', transition: 'width 1s cubic-bezier(0.4, 0, 0.2, 1)' }} />
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* MODAL MODERNO E COLORIDO (LISTA DE COMPRAS) */}
      {selectedCartao && (
        <div className="modal-overlay" onClick={fecharModais} style={{ backdropFilter: 'blur(8px)', backgroundColor: 'rgba(15, 23, 42, 0.6)' }}>
          <div className="modal-content fade-in" onClick={e => e.stopPropagation()} 
            style={{ 
              maxWidth: '550px', width: '95%', borderRadius: '32px', padding: '0', overflow: 'hidden',
              boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.5)'
            }}>
            
            {/* Header Colorido do Modal */}
            <div style={{ background: selectedCartao.cor, padding: '40px 30px', color: 'white', position: 'relative' }}>
               <button onClick={fecharModais} style={{ position: 'absolute', top: '20px', right: '20px', background: 'rgba(0,0,0,0.2)', border: 'none', color: 'white', borderRadius: '50%', width: '36px', height: '36px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                 <X size={20} />
               </button>
               <h2 style={{ margin: 0, fontSize: '1.8rem', fontWeight: '800' }}>{selectedCartao.nome}</h2>
               <div style={{ display: 'flex', gap: '20px', marginTop: '15px' }}>
                  <div style={{ background: 'rgba(255,255,255,0.2)', padding: '8px 16px', borderRadius: '12px', fontSize: '0.85rem' }}>
                    Faturamento: Dia <strong>{selectedCartao.dia_fechamento}</strong>
                  </div>
                  <div style={{ background: 'rgba(255,255,255,0.2)', padding: '8px 16px', borderRadius: '12px', fontSize: '0.85rem' }}>
                    Limite: <strong>{formatMoney(selectedCartao.limite)}</strong>
                  </div>
               </div>
            </div>

            <div style={{ padding: '30px', background: 'white' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '20px', color: 'var(--text-main)' }}>
                 <ShoppingCart size={18} />
                 <h4 style={{ margin: 0 }}>Lançamentos do Mês</h4>
              </div>

              <div style={{ maxHeight: '350px', overflowY: 'auto', paddingRight: '5px' }}>
                {compras.filter(c => c.cartao === selectedCartao.nome).map((item, idx) => {
                  const numParcelas = item.num_parcelas || 1;
                  let parcelaInfo = null;

                  for (let i = 0; i < numParcelas; i++) {
                    const dC = new Date(item.data_compra);
                    const dP = new Date(dC.getFullYear(), dC.getMonth() + i, 1);
                    if (dP.getMonth() === mesAtual && dP.getFullYear() === anoAtual) {
                      parcelaInfo = { atual: i + 1, total: numParcelas, valor: parseFloat(item.valor_total) / numParcelas };
                    }
                  }

                  if (!parcelaInfo) return null;

                  return (
                    <div key={idx} style={{ 
                      display: 'flex', justifyContent: 'space-between', padding: '16px', 
                      borderRadius: '16px', marginBottom: '12px', background: '#f8fafc',
                      border: '1px solid #f1f5f9', alignItems: 'center'
                    }}>
                      <div style={{ display: 'flex', gap: '15px', alignItems: 'center' }}>
                        <div style={{ background: `${selectedCartao.cor}15`, color: selectedCartao.cor, padding: '10px', borderRadius: '12px' }}>
                           <ArrowUpRight size={20} />
                        </div>
                        <div>
                          <div style={{ fontWeight: '700', fontSize: '0.95rem', color: '#1e293b' }}>{item.descricao}</div>
                          <div style={{ fontSize: '0.8rem', color: '#64748b', marginTop: '2px' }}>
                            {new Date(item.data_compra).toLocaleDateString('pt-BR')}
                            {item.parcelado && <span style={{ marginLeft: '8px', color: 'var(--primary)', fontWeight: '700' }}>({parcelaInfo.atual}/{parcelaInfo.total})</span>}
                          </div>
                        </div>
                      </div>
                      <div style={{ fontWeight: '800', color: '#1e293b', fontSize: '1rem' }}>{formatMoney(parcelaInfo.valor)}</div>
                    </div>
                  );
                })}
              </div>
              
              <button onClick={fecharModais} className="btn-primary" style={{ width: '100%', marginTop: '25px', background: '#0f172a', borderRadius: '16px' }}>
                Fechar Visualização (ESC)
              </button>
            </div>
          </div>
        </div>
      )}

      {/* MODAL DE CADASTRO (IGUALMENTE MODERNO) */}
      {showModal && (
        <div className="modal-overlay" onClick={fecharModais} style={{ backdropFilter: 'blur(8px)' }}>
          <div className="modal-content" onClick={e => e.stopPropagation()} style={{ borderRadius: '24px', padding: '30px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '25px' }}>
               <h3 style={{ margin: 0, fontSize: '1.5rem', fontWeight: '800' }}>Novo Cartão</h3>
               <X style={{ cursor: 'pointer' }} onClick={fecharModais} />
            </div>
            
            <form onSubmit={handleSave} style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
               <div>
                 <label style={{ fontSize: '0.75rem', fontWeight: '700', textTransform: 'uppercase', color: '#64748b' }}>Instituição</label>
                 <input className="form-control" placeholder="Ex: Nubank" required onChange={e => setNovoCartao({...novoCartao, nome: e.target.value})} />
               </div>
               
               <div>
                 <label style={{ fontSize: '0.75rem', fontWeight: '700', textTransform: 'uppercase', color: '#64748b' }}>Limite Total</label>
                 <input className="form-control" type="number" placeholder="0.00" required onChange={e => setNovoCartao({...novoCartao, limite: e.target.value})} />
               </div>

               <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px' }}>
                  <div>
                    <label style={{ fontSize: '0.75rem', fontWeight: '700', textTransform: 'uppercase', color: '#64748b' }}>Fechamento</label>
                    <input className="form-control" type="number" placeholder="Dia" onChange={e => setNovoCartao({...novoCartao, dia_fechamento: e.target.value})} />
                  </div>
                  <div>
                    <label style={{ fontSize: '0.75rem', fontWeight: '700', textTransform: 'uppercase', color: '#64748b' }}>Vencimento</label>
                    <input className="form-control" type="number" placeholder="Dia" onChange={e => setNovoCartao({...novoCartao, dia_vencimento: e.target.value})} />
                  </div>
               </div>

               <div>
                 <label style={{ fontSize: '0.75rem', fontWeight: '700', textTransform: 'uppercase', color: '#64748b' }}>Personalização (Cor)</label>
                 <input type="color" className="form-control" value={novoCartao.cor} onChange={e => setNovoCartao({...novoCartao, cor: e.target.value})} style={{ height: '50px', padding: '4px' }} />
               </div>

               <button type="submit" className="btn-primary" style={{ height: '55px', borderRadius: '16px', fontSize: '1rem', fontWeight: '700', marginTop: '10px' }}>
                 Criar Cartão
               </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

const navBtnStyle = { background: 'none', border: 'none', cursor: 'pointer', color: 'var(--primary)' };

export default Cartoes;
